import{_ as a,c as i,o as s,a1 as l}from"./chunks/framework.DILC4Csi.js";const c=JSON.parse('{"title":"Ключевые концепции: Единая экосистема навыков | OpenSkills","description":"Изучите ключевые концепции и принципы работы OpenSkills. Как унифицированный загрузчик навыков, поддерживает многопользовательский доступ и обеспечивает постепенную загрузку.","frontmatter":{"title":"Ключевые концепции: Единая экосистема навыков | OpenSkills","sidebarTitle":"Позвольте ИИ-инструментам делиться навыками","subtitle":"Ключевые концепции: Единая экосистема навыков | OpenSkills","description":"Изучите ключевые концепции и принципы работы OpenSkills. Как унифицированный загрузчик навыков, поддерживает многопользовательский доступ и обеспечивает постепенную загрузку.","tags":["Введение в концепции","Ключевые концепции"],"prerequisite":[],"order":2},"headers":[],"relativePath":"ru/numman-ali/openskills/start/what-is-openskills/index.md","filePath":"ru/numman-ali/openskills/start/what-is-openskills/index.md"}'),e={name:"ru/numman-ali/openskills/start/what-is-openskills/index.md"};function n(d,t,r,o,h,p){return s(),i("div",null,[...t[0]||(t[0]=[l(`<h1 id="что-такое-openskills" tabindex="-1">Что такое OpenSkills? <a class="header-anchor" href="#что-такое-openskills" aria-label="Permalink to &quot;Что такое OpenSkills?&quot;">​</a></h1><h2 id="что-вы-сможете-делать-после-прохождения" tabindex="-1">Что вы сможете делать после прохождения <a class="header-anchor" href="#что-вы-сможете-делать-после-прохождения" aria-label="Permalink to &quot;Что вы сможете делать после прохождения&quot;">​</a></h2><ul><li>Понимать ключевую ценность и принципы работы OpenSkills</li><li>Знать о связи между OpenSkills и Claude Code</li><li>Определять, когда использовать OpenSkills вместо встроенной системы навыков</li><li>Понимать, как несколько ИИ-агентов кодирования могут совместно использовать экосистему навыков</li></ul><div class="info custom-block"><p class="custom-block-title">Необходимые знания</p><p>Этот туториал предполагает, что вы знакомы с основными ИИ-инструментами кодирования (такими как Claude Code, Cursor и др.), но не требует опыта работы с OpenSkills.</p></div><hr><h2 id="ваша-текущая-проблема" tabindex="-1">Ваша текущая проблема <a class="header-anchor" href="#ваша-текущая-проблема" aria-label="Permalink to &quot;Ваша текущая проблема&quot;">​</a></h2><p>Вы можете столкнуться со следующими сценариями:</p><ul><li><strong>Навыки, привычные в Claude Code, исчезают при смене ИИ-инструмента</strong>: например, навыки обработки PDF в Claude Code недоступны в Cursor</li><li><strong>Повторная установка навыков в разных инструментах</strong>: каждый ИИ-инструмент требует отдельной настройки навыков, что увеличивает затраты на управление</li><li><strong>Невозможность использовать частные навыки через официальный Marketplace</strong>: внутренние или собственные навыки компании невозможно удобно делиться с командой</li></ul><p>Суть этих проблем: <strong>отсутствие единого формата навыков, невозможность совместного использования между инструментами</strong>.</p><hr><h2 id="ключевая-идея-унификация-формата-навыков" tabindex="-1">Ключевая идея: Унификация формата навыков <a class="header-anchor" href="#ключевая-идея-унификация-формата-навыков" aria-label="Permalink to &quot;Ключевая идея: Унификация формата навыков&quot;">​</a></h2><p>Ключевая идея OpenSkills проста: <strong>превратить систему навыков Claude Code в универсальный загрузчик навыков</strong>.</p><h3 id="что-это-такое" tabindex="-1">Что это такое <a class="header-anchor" href="#что-это-такое" aria-label="Permalink to &quot;Что это такое&quot;">​</a></h3><p><strong>OpenSkills</strong> — это универсальный загрузчик системы навыков Anthropic, позволяющий любому ИИ-агенту кодирования (Claude Code, Cursor, Windsurf, Aider и др.) использовать навыки в стандартном формате SKILL.md.</p><p>Проще говоря: <strong>один установщик для всех ИИ-инструментов кодирования</strong>.</p><h3 id="какие-проблемы-решает" tabindex="-1">Какие проблемы решает <a class="header-anchor" href="#какие-проблемы-решает" aria-label="Permalink to &quot;Какие проблемы решает&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Проблема</th><th>Решение</th></tr></thead><tbody><tr><td>Разнообразие форматов навыков</td><td>Использование стандартного формата SKILL.md Claude Code</td></tr><tr><td>Невозможность совместного использования навыков между инструментами</td><td>Генерация единого AGENTS.md, читаемого всеми инструментами</td></tr><tr><td>Распределённое управление навыками</td><td>Единые команды установки, обновления и удаления</td></tr><tr><td>Сложность обмена частными навыками</td><td>Поддержка установки из локальных путей и частных git-репозиториев</td></tr></tbody></table><hr><h2 id="ключевая-ценность" tabindex="-1">Ключевая ценность <a class="header-anchor" href="#ключевая-ценность" aria-label="Permalink to &quot;Ключевая ценность&quot;">​</a></h2><p>OpenSkills предоставляет следующую ключевую ценность:</p><h3 id="_1-унифицированныи-стандарт" tabindex="-1">1. Унифицированный стандарт <a class="header-anchor" href="#_1-унифицированныи-стандарт" aria-label="Permalink to &quot;1. Унифицированный стандарт&quot;">​</a></h3><p>Все агенты используют один и тот же формат навыков и описание AGENTS.md, не требуя изучения новых форматов.</p><ul><li><strong>Полная совместимость с Claude Code</strong>: одинаковый формат подсказок, Marketplace, структура папок</li><li><strong>Стандартизированный SKILL.md</strong>: чёткое определение навыка, удобное для разработки и поддержки</li></ul><h3 id="_2-постепенная-загрузка" tabindex="-1">2. Постепенная загрузка <a class="header-anchor" href="#_2-постепенная-загрузка" aria-label="Permalink to &quot;2. Постепенная загрузка&quot;">​</a></h3><p>Загрузка навыков по требованию, поддержание краткого контекста ИИ.</p><ul><li>Не нужно загружать все навыки сразу</li><li>ИИ-агент динамически загружает соответствующие навыки по требованию задачи</li><li>Избегает перегрузки контекста, улучшая качество ответов</li></ul><h3 id="_3-поддержка-нескольких-агентов" tabindex="-1">3. Поддержка нескольких агентов <a class="header-anchor" href="#_3-поддержка-нескольких-агентов" aria-label="Permalink to &quot;3. Поддержка нескольких агентов&quot;">​</a></h3><p>Один набор навыков для нескольких агентов, без повторной установки.</p><ul><li>Claude Code, Cursor, Windsurf, Aider совместно используют один и тот же набор навыков</li><li>Унифицированный интерфейс управления навыками</li><li>Снижение затрат на конфигурацию и поддержку</li></ul><h3 id="_4-дружелюбность-к-open-source" tabindex="-1">4. Дружелюбность к open source <a class="header-anchor" href="#_4-дружелюбность-к-open-source" aria-label="Permalink to &quot;4. Дружелюбность к open source&quot;">​</a></h3><p>Поддержка локальных путей и частных git-репозиториев, подходит для командной работы.</p><ul><li>Установка навыков из локальной файловой системы (в разработке)</li><li>Установка из частных git-репозиториев (внутренний обмен компании)</li><li>Навыки можно управлять версиями вместе с проектом</li></ul><h3 id="_5-локальное-выполнение" tabindex="-1">5. Локальное выполнение <a class="header-anchor" href="#_5-локальное-выполнение" aria-label="Permalink to &quot;5. Локальное выполнение&quot;">​</a></h3><p>Нет загрузки данных, безопасность конфиденциальности.</p><ul><li>Все файлы навыков хранятся локально</li><li>Нет зависимости от облачных сервисов, нет риска утечки данных</li><li>Подходит для конфиденциальных проектов и корпоративных сред</li></ul><hr><h2 id="как-это-работает" tabindex="-1">Как это работает <a class="header-anchor" href="#как-это-работает" aria-label="Permalink to &quot;Как это работает&quot;">​</a></h2><p>Рабочий процесс OpenSkills очень прост, состоит из трёх шагов:</p><h3 id="шаг-1-установка-навыка" tabindex="-1">Шаг 1: Установка навыка <a class="header-anchor" href="#шаг-1-установка-навыка" aria-label="Permalink to &quot;Шаг 1: Установка навыка&quot;">​</a></h3><p>Установите навык из GitHub, локального пути или частного git-репозитория в ваш проект.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Установка из официального репозитория Anthropic</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> anthropics/skills</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># Установка из локального пути</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> install</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ./my-skills</span></span></code></pre></div><p>Навыки будут установлены в каталог <code>.claude/skills/</code> проекта (по умолчанию) или <code>.agent/skills/</code> (при использовании <code>--universal</code>).</p><h3 id="шаг-2-синхронизация-в-agents-md" tabindex="-1">Шаг 2: Синхронизация в AGENTS.md <a class="header-anchor" href="#шаг-2-синхронизация-в-agents-md" aria-label="Permalink to &quot;Шаг 2: Синхронизация в AGENTS.md&quot;">​</a></h3><p>Синхронизируйте установленные навыки в файл AGENTS.md, сгенерируйте список навыков, читаемый ИИ-агентом.</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> sync</span></span></code></pre></div><p>AGENTS.md будет содержать XML, подобный этому:</p><div class="language-xml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">xml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">available_skills</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">skill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;pdf&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">name</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;Comprehensive PDF manipulation toolkit for extracting text and tables...&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">description</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">location</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;project&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">location</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">skill</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&lt;/</span><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">available_skills</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">&gt;</span></span></code></pre></div><h3 id="шаг-3-загрузка-навыка-ии-агентом" tabindex="-1">Шаг 3: Загрузка навыка ИИ-агентом <a class="header-anchor" href="#шаг-3-загрузка-навыка-ии-агентом" aria-label="Permalink to &quot;Шаг 3: Загрузка навыка ИИ-агентом&quot;">​</a></h3><p>Когда ИИ-агенту нужно использовать навык, загрузите содержимое навыка следующей командой:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">openskills</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> read</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">skill-nam</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">e</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span></code></pre></div><p>ИИ-агент динамически загружает содержимое навыка в контекст и выполняет задачу.</p><hr><h2 id="отношения-с-claude-code" tabindex="-1">Отношения с Claude Code <a class="header-anchor" href="#отношения-с-claude-code" aria-label="Permalink to &quot;Отношения с Claude Code&quot;">​</a></h2><p>OpenSkills и Claude Code дополняют друг друга, а не заменяют.</p><h3 id="полная-совместимость-форматов" tabindex="-1">Полная совместимость форматов <a class="header-anchor" href="#полная-совместимость-форматов" aria-label="Permalink to &quot;Полная совместимость форматов&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Аспект</th><th>Claude Code</th><th>OpenSkills</th></tr></thead><tbody><tr><td><strong>Формат подсказок</strong></td><td><code>&lt;available_skills&gt;</code> XML</td><td>Тот же XML</td></tr><tr><td><strong>Хранение навыков</strong></td><td><code>.claude/skills/</code></td><td><code>.claude/skills/</code> (по умолчанию)</td></tr><tr><td><strong>Вызов навыка</strong></td><td>Инструмент <code>Skill(&quot;name&quot;)</code></td><td><code>npx openskills read &lt;name&gt;</code></td></tr><tr><td><strong>Marketplace</strong></td><td>Маркетплейс Anthropic</td><td>GitHub (anthropics/skills)</td></tr><tr><td><strong>Постепенная загрузка</strong></td><td>✅</td><td>✅</td></tr></tbody></table><h3 id="сравнение-сценариев-использования" tabindex="-1">Сравнение сценариев использования <a class="header-anchor" href="#сравнение-сценариев-использования" aria-label="Permalink to &quot;Сравнение сценариев использования&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Сценарий</th><th>Рекомендуемый инструмент</th><th>Причина</th></tr></thead><tbody><tr><td>Только Claude Code</td><td>Встроенный Claude Code</td><td>Не требует дополнительной установки, официальная поддержка</td></tr><tr><td>Смешанное использование нескольких ИИ-инструментов</td><td>OpenSkills</td><td>Единое управление, избежание дублирования</td></tr><tr><td>Нужны частные навыки</td><td>OpenSkills</td><td>Поддержка локальных и частных репозиториев</td></tr><tr><td>Командная совместная работа</td><td>OpenSkills</td><td>Навыки можно управлять версиями, легко делиться</td></tr></tbody></table><hr><h2 id="описание-мест-установки" tabindex="-1">Описание мест установки <a class="header-anchor" href="#описание-мест-установки" aria-label="Permalink to &quot;Описание мест установки&quot;">​</a></h2><p>OpenSkills поддерживает три места установки:</p><table tabindex="0"><thead><tr><th>Место установки</th><th>Команда</th><th>Сценарий использования</th></tr></thead><tbody><tr><td><strong>Локально в проекте</strong></td><td>По умолчанию</td><td>Использование в одном проекте, навыки управляются версиями вместе с проектом</td></tr><tr><td><strong>Глобальная установка</strong></td><td><code>--global</code></td><td>Общие часто используемые навыки для всех проектов</td></tr><tr><td><strong>Universal-режим</strong></td><td><code>--universal</code></td><td>Многопользовательская среда, избежание конфликтов с Claude Code</td></tr></tbody></table><div class="tip custom-block"><p class="custom-block-title">Когда использовать Universal-режим?</p><p>Если вы одновременно используете Claude Code и другие ИИ-агенты кодирования (такие как Cursor, Windsurf), используйте <code>--universal</code> для установки в <code>.agent/skills/</code>, чтобы несколько агентов могли совместно использовать один набор навыков, избегая конфликтов.</p></div><hr><h2 id="экосистема-навыков" tabindex="-1">Экосистема навыков <a class="header-anchor" href="#экосистема-навыков" aria-label="Permalink to &quot;Экосистема навыков&quot;">​</a></h2><p>OpenSkills использует ту же экосистему навыков, что и Claude Code:</p><h3 id="официальная-библиотека-навыков" tabindex="-1">Официальная библиотека навыков <a class="header-anchor" href="#официальная-библиотека-навыков" aria-label="Permalink to &quot;Официальная библиотека навыков&quot;">​</a></h3><p>Официальное хранилище навыков от Anthropic: <a href="https://github.com/anthropics/skills" target="_blank" rel="noreferrer">anthropics/skills</a></p><p>Включает часто используемые навыки:</p><ul><li>Обработка PDF</li><li>Генерация изображений</li><li>Анализ данных</li><li>и др.</li></ul><h3 id="навыки-сообщества" tabindex="-1">Навыки сообщества <a class="header-anchor" href="#навыки-сообщества" aria-label="Permalink to &quot;Навыки сообщества&quot;">​</a></h3><p>Любой репозиторий на GitHub может быть источником навыков, достаточно наличия файла SKILL.md.</p><h3 id="пользовательские-навыки" tabindex="-1">Пользовательские навыки <a class="header-anchor" href="#пользовательские-навыки" aria-label="Permalink to &quot;Пользовательские навыки&quot;">​</a></h3><p>Вы можете создавать свои навыки, используя стандартный формат, и делиться ими с командой.</p><hr><h2 id="резюме-урока" tabindex="-1">Резюме урока <a class="header-anchor" href="#резюме-урока" aria-label="Permalink to &quot;Резюме урока&quot;">​</a></h2><p>Ключевая идея OpenSkills:</p><ol><li><strong>Унифицированный стандарт</strong>: использование формата SKILL.md Claude Code</li><li><strong>Поддержка нескольких агентов</strong>: все ИИ-инструменты кодирования совместно используют экосистему навыков</li><li><strong>Постепенная загрузка</strong>: загрузка по требованию, поддержание краткого контекста</li><li><strong>Локальное выполнение</strong>: нет загрузки данных, безопасность конфиденциальности</li><li><strong>Дружелюбие к open source</strong>: поддержка локальных и частных репозиториев</li></ol><p>С помощью OpenSkills вы можете:</p><ul><li>Бесшовно переключаться между разными ИИ-инструментами</li><li>Единообразно управлять всеми навыками</li><li>Использовать и делиться частными навыками</li><li>Повышать эффективность разработки</li></ul><hr><h2 id="анонс-следующего-урока" tabindex="-1">Анонс следующего урока <a class="header-anchor" href="#анонс-следующего-урока" aria-label="Permalink to &quot;Анонс следующего урока&quot;">​</a></h2><blockquote><p>На следующем уроке мы изучим <strong><a href="./../installation/">Установка инструмента OpenSkills</a></strong></p><p>Вы узнаете:</p><ul><li>Как проверить среду Node.js и Git</li><li>Как установить OpenSkills с помощью npx или глобально</li><li>Как проверить успешность установки</li><li>Как решить распространённые проблемы установки</li></ul></blockquote><hr><h2 id="приложение-справочник-по-исходному-коду" tabindex="-1">Приложение: Справочник по исходному коду <a class="header-anchor" href="#приложение-справочник-по-исходному-коду" aria-label="Permalink to &quot;Приложение: Справочник по исходному коду&quot;">​</a></h2><details><summary><strong>Нажмите, чтобы просмотреть расположение исходного кода</strong></summary><blockquote><p>Последнее обновление: 2026-01-24</p></blockquote><table tabindex="0"><thead><tr><th>Функция</th><th>Путь к файлу</th><th>Номер строки</th></tr></thead><tbody><tr><td>Определение основных типов</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L1-L24" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>1-24</td></tr><tr><td>Интерфейс навыка (Skill)</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L1-L6" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>1-6</td></tr><tr><td>Интерфейс расположения навыка (SkillLocation)</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L8-L12" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>8-12</td></tr><tr><td>Интерфейс опций установки (InstallOptions)</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L14-L18" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>14-18</td></tr><tr><td>Интерфейс метаданных навыка (SkillMetadata)</td><td><a href="https://github.com/numman-ali/openskills/blob/main/src/types.ts#L20-L24" target="_blank" rel="noreferrer"><code>src/types.ts</code></a></td><td>20-24</td></tr></tbody></table><p><strong>Ключевые интерфейсы</strong>:</p><ul><li><code>Skill</code>: информация об установленном навыке (name, description, location, path)</li><li><code>SkillLocation</code>: информация о месте поиска навыка (path, baseDir, source)</li><li><code>InstallOptions</code>: опции команды установки (global, universal, yes)</li><li><code>SkillMetadata</code>: метаданные навыка (name, description, context)</li></ul><p><strong>Источник ключевых концепций</strong>:</p><ul><li>README.md:22-86 - раздел &quot;What Is OpenSkills?&quot;</li></ul></details>`,86)])])}const u=a(e,[["render",n]]);export{c as __pageData,u as default};
